from pymongo import MongoClient
import sys

class AdvancedDataFilterService:
    def __init__(self, connection_string, database_name):
        self.client = MongoClient(connection_string)
        self.db = self.client[database_name]
    
    def execute_where_query(self, collection_name, javascript_expression):
        """
        Execute a MongoDB query using $where operator with server-side JavaScript
        """
        try:
            collection = self.db[collection_name]
            
            # Construct the query using $where operator
            query = {
                "$where": javascript_expression
            }
            
            # Execute the query
            cursor = collection.find(query)
            
            # Convert cursor to list of documents
            results = list(cursor)
            
            return results
            
        except Exception as e:
            print(f"Error executing query: {str(e)}")
            return []
    
    def execute_complex_where_query(self, collection_name, javascript_expression, 
                                  projection=None, sort_field=None, sort_order=1, 
                                  limit=None):
        """
        Execute a complex MongoDB query with additional options
        """
        try:
            collection = self.db[collection_name]
            
            # Construct the query using $where operator
            query = {
                "$where": javascript_expression
            }
            
            # Build the aggregation pipeline
            pipeline = [{"$match": query}]
            
            # Add projection if specified
            if projection:
                pipeline.append({"$project": projection})
            
            # Add sorting if specified
            if sort_field:
                pipeline.append({"$sort": {sort_field: sort_order}})
            
            # Add limit if specified
            if limit:
                pipeline.append({"$limit": limit})
            
            # Execute the aggregation pipeline
            cursor = collection.aggregate(pipeline)
            
            # Convert cursor to list of documents
            results = list(cursor)
            
            return results
            
        except Exception as e:
            print(f"Error executing complex query: {str(e)}")
            return []
    
    def validate_javascript_expression(self, expression):
        """
        Basic validation of JavaScript expression (sanitization)
        """
        # Simple validation - check for dangerous patterns
        dangerous_patterns = ['db.', 'forEach', 'map', 'reduce', 'eval']
        
        for pattern in dangerous_patterns:
            if pattern in expression:
                raise ValueError(f"Potentially dangerous pattern '{pattern}' found in expression")
        
        return True

